#include <bits/stdc++.h>
using namespace std;
int k,x,y,a[350004],b[350004],c[350004],sum;
void dfs(int sx,int sy,int ex,int ey,int t){
    if(sx==ex && sy==ey)
        return;
    int mx=(sx+ex)/2,my=(sy+ey)/2;
    if(t==0){
        if(x>=sx && y>=sy && x<=mx && y<=my)
            sum++,a[sum]=mx+1,b[sum]=my+1,c[sum]=1,dfs(sx,sy,mx,my,0),dfs(sx,my+1,mx,ey,1),dfs(mx+1,sy,ex,my,3),dfs(mx+1,my+1,ex,ey,2);
        else if(x>=sx && y>my && x<=mx && y<=ey)
            sum++,a[sum]=mx+1,b[sum]=my,c[sum]=2,dfs(sx,sy,mx,my,4),dfs(sx,my+1,mx,ey,0),dfs(mx+1,sy,ex,my,3),dfs(mx+1,my+1,ex,ey,2);
        else if(x>mx && y>=sy && x<=ex && y<=my)
            sum++,a[sum]=mx,b[sum]=my+1,c[sum]=3,dfs(sx,sy,mx,my,4),dfs(sx,my+1,mx,ey,1),dfs(mx+1,sy,ex,my,0),dfs(mx+1,my+1,ex,ey,2);
        else
            sum++,a[sum]=mx,b[sum]=my,c[sum]=4,dfs(sx,sy,mx,my,4),dfs(sx,my+1,mx,ey,1),dfs(mx+1,sy,ex,my,3),dfs(mx+1,my+1,ex,ey,0);
    }else if(t==1){
        sum++,a[sum]=mx,b[sum]=my+1,c[sum]=3,dfs(sx,sy,mx,my,4),dfs(sx,my+1,mx,ey,1),dfs(mx+1,sy,ex,my,1),dfs(mx+1,my+1,ex,ey,2);
    }else if(t==2){
        sum++,a[sum]=mx+1,b[sum]=my+1,c[sum]=1,dfs(sx,sy,mx,my,2),dfs(sx,my+1,mx,ey,1),dfs(mx+1,sy,ex,my,3),dfs(mx+1,my+1,ex,ey,2);
    }else if(t==3){
        sum++,a[sum]=mx+1,b[sum]=my,c[sum]=2,dfs(sx,sy,mx,my,4),dfs(sx,my+1,mx,ey,3),dfs(mx+1,sy,ex,my,3),dfs(mx+1,my+1,ex,ey,2);
    }else{
        sum++,a[sum]=mx,b[sum]=my,c[sum]=4,dfs(sx,sy,mx,my,4),dfs(sx,my+1,mx,ey,1),dfs(mx+1,sy,ex,my,3),dfs(mx+1,my+1,ex,ey,4);
    }
}
int main(){
    scanf("%d%d%d",&k,&x,&y);
    k=1<<k;
    dfs(1,1,k,k,0);
    for(int i=1;i<=sum;i++)
        printf("%d %d %d\n",a[i],b[i],c[i]);
    return 0;
}
